import java.lang.reflect.Method;

public class ReflectionExample {
    public static void main(String[] args) throws Exception {
        Class<?> stringClass = Class.forName("java.lang.String");
        Method lengthMethod = stringClass.getMethod("length");
        String testString = "Hello";
        System.out.println(lengthMethod.invoke(testString)); // Invokes 'length()' on 'testString'
    }
}

import java.io.FileInputStream;
import java.io.IOException;

public class ResourceHandling {
    public static void main(String[] args) {
        try (FileInputStream fis = new FileInputStream("nonexistent.txt")) {
            System.out.println("File opened.");
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
            for (Throwable t : e.getSuppressed()) {
                System.err.println("Suppressed: " + t.getMessage());
            }
        }
    }
}
